## breakの基本

`break` はループを即座に終了し、ループの後の処理に移ります。

```javascript
var items = ['item_a', 'item_b', 'target_item', 'item_c'];
var found = null;

for (var i = 0; i < items.length; i++) {
  if (items[i] === 'target_item') {
    found = items[i];
    break;  // 見つかったらループを終了
  }
}
console.log(found);  // 'target_item'
```

## continueの基本

`continue` は現在のイテレーションの残りの処理をスキップし、次のイテレーションに進みます。

```javascript
var numbers = [1, -2, 3, -4, 5];
var positiveSum = 0;

for (var i = 0; i < numbers.length; i++) {
  if (numbers[i] < 0) {
    continue;  // 負の数はスキップ
  }
  positiveSum += numbers[i];  // 正の数のみ加算
}
console.log(positiveSum);  // 9（1+3+5）
```

### GTM実例①：dataLayerから特定イベントを検索

```javascript
<script>
  var dataLayer = window.dataLayer || [];
  var purchaseEvent = null;

  // dataLayerを新しい順に検索し、最初のpurchaseを取得
  for (var i = dataLayer.length - 1; i >= 0; i--) {
    if (dataLayer[i] && dataLayer[i].event === 'purchase') {
      purchaseEvent = dataLayer[i];
      break;  // 見つかったらループを終了（残りを検索しない）
    }
  }

  if (purchaseEvent) {
    console.log('購入金額:', purchaseEvent.ecommerce.value);
  }
</script>
```

### GTM実例②：不正アイテムを除外してGA4 itemsを構築

```javascript
<script>
  var rawItems = {{Raw Product Data}};
  var validItems = [];

  for (var i = 0; i < rawItems.length; i++) {
    var item = rawItems[i];

    // 必須パラメータがない場合はスキップ
    if (!item.id || !item.name || !item.price) {
      continue;  // このアイテムは処理せず次へ
    }

    // 価格が不正（0以下）な場合はスキップ
    if (item.price <= 0) {
      continue;
    }

    // 有効なアイテムのみGA4形式に変換
    validItems.push({
      'item_id': item.id,
      'item_name': item.name,
      'price': item.price,
      'quantity': item.quantity || 1
    });
  }

  window.dataLayer = window.dataLayer || [];
  window.dataLayer.push({
    'event': 'view_item_list',
    'ecommerce': { 'items': validItems }
  });
</script>
```

### breakとcontinueの違いの整理

```javascript
var data = [1, 2, 'STOP', 3, 4];

// break：'STOP'に到達したらループ全体を終了
for (var i = 0; i < data.length; i++) {
  if (data[i] === 'STOP') break;
  console.log(data[i]);  // 1, 2
}

// continue：'STOP'をスキップして続行
for (var i = 0; i < data.length; i++) {
  if (data[i] === 'STOP') continue;
  console.log(data[i]);  // 1, 2, 3, 4
}
```

